 1→import { useCallback, useEffect, useRef, useState } from 'react';
 2→import { isTauri } from '../platform';
 3→
 4→export function useDbSearch<TRow, TEntry>(
 5→  query: string,
 6→  dbSearch: (query: string) => Promise<TRow[]>,
 7→  rowToEntry: (row: TRow) => TEntry,
 8→): {
 9→  results: TEntry[] | null;
10→  invalidate: () => void;
11→} {
12→  const [results, setResults] = useState<TEntry[] | null>(null);
13→  const requestIdRef = useRef(0);
14→
15→  const invalidate = useCallback(() => {
16→    requestIdRef.current++;
17→    setResults(null);
18→  }, []);
19→
20→  useEffect(() => {
21→    if (!isTauri || !query.trim()) {
22→      setResults(null);
23→      return;
24→    }
25→
26→    const requestId = ++requestIdRef.current;
27→    let cancelled = false;
28→
29→    dbSearch(query)
30→      .then(rows => {
31→        if (cancelled || requestId !== requestIdRef.current) {
32→          return;
33→        }
34→        setResults(rows.map(rowToEntry));
35→      })
36→      .catch(err => {
37→        console.error('FTS5 search failed:', err);
38→        if (!cancelled && requestId === requestIdRef.current) {
39→          setResults(null);
40→        }
41→      });
42→
43→    return () => {
44→      cancelled = true;
45→    };
46→  }, [
47→    query,
48→    dbSearch,
49→    rowToEntry,
50→  ]);
51→
52→  return {
53→    results,
54→    invalidate,
55→  };
56→}
