 82→export function EmojiPickerView() {
 83→  const nav = useNavigation();
 84→  const [query, setQuery] = useState('');
 85→  const [filterValue, setFilterValue] = useState('all');
 86→  const [activeIndex, setActiveIndex] = useState(0);
 87→  const [actionsOpen, setActionsOpen] = useState(false);
 88→  const [recentChars, setRecentChars] = useState<string[]>([]);
 89→
 90→  useEffect(() => {
 91→    let cancelled = false;
 92→    settingsDb
 93→      .get(DB_KEY)
 94→      .then(raw => {
 95→        if (!cancelled) setRecentChars(parseRecentEmojis(raw));
 96→      })
 97→      .catch(console.error);
 98→    return () => {
 99→      cancelled = true;
100→    };
101→  }, []);
102→  const { items: hudItems, show: showHUD } = useHUD();
103→  const containerRef = useRef<HTMLDivElement>(null);
104→
105→  const emojiLookup = useMemo(() => {
106→    const map = new Map<string, EmojiEntry>();
107→    for (const e of MOCK_EMOJIS) {
108→      map.set(e.char, e);
109→    }
110→    return map;
111→  }, []);
112→
113→  const recentEmojis = useMemo(
114→    () =>
115→      recentChars
116→        .map(char => emojiLookup.get(char))
117→        .filter((e): e is EmojiEntry => e !== undefined),
118→    [
119→      recentChars,
120→      emojiLookup,
121→    ],
122→  );
123→
124→  const filtered = useMemo(() => {
125→    let emojis = MOCK_EMOJIS;
126→    if (filterValue !== 'all') {
127→      emojis = emojis.filter(e => e.category === filterValue);
128→    }
129→    if (query) {
130→      emojis = emojis.filter(
131→        e =>
132→          fuzzyMatch(query, e.name) ||
133→          e.keywords.some(k => fuzzyMatch(query, k)) ||
134→          e.char === query,
135→      );
136→    }
137→    return emojis;
138→  }, [
139→    query,
140→    filterValue,
141→  ]);
142→
143→  const sections = useMemo(() => {
144→    const result: EmojiSection[] = [];
145→
146→    if (!query && filterValue === 'all' && recentEmojis.length > 0) {
147→      result.push({
148→        title: 'Recently Used',
149→        emojis: recentEmojis,
150→      });
151→    }
152→
153→    const grouped = new Map<EmojiCategory, EmojiEntry[]>();
154→    for (const emoji of filtered) {
155→      const existing = grouped.get(emoji.category);
156→      if (existing) {
157→        existing.push(emoji);
158→      } else {
159→        grouped.set(emoji.category, [emoji]);
160→      }
161→    }
162→
163→    for (const cat of EMOJI_CATEGORY_ORDER) {
164→      const items = grouped.get(cat);
165→      if (items && items.length > 0) {
166→        result.push({
167→          title: EMOJI_CATEGORY_LABELS[cat],
168→          emojis: items,
169→        });
170→      }
171→    }
172→
173→    return result;
174→  }, [
175→    filtered,
176→    query,
177→    filterValue,
178→    recentEmojis,
179→  ]);
180→
181→  const flatEmojis = useMemo(() => sections.flatMap(s => s.emojis), [sections]);
182→  const totalCount = flatEmojis.length;
183→
184→  useEffect(() => {
185→    if (totalCount === 0) {
186→      setActiveIndex(0);
187→    } else if (activeIndex >= totalCount) {
188→      setActiveIndex(totalCount - 1);
189→    }
190→  }, [
191→    totalCount,
192→    activeIndex,
193→  ]);
194→
195→  useEffect(() => {
196→    const container = containerRef.current;
197→    if (!container) return;
198→    const el = container.querySelector<HTMLElement>(
199→      `[data-emoji-index="${activeIndex}"]`,
200→    );
201→    el?.scrollIntoView({ block: 'nearest' });
202→  }, [activeIndex]);
203→
204→  const selectedEmoji = flatEmojis[activeIndex];
205→
206→  const addToRecent = useCallback((char: string) => {
207→    setRecentChars(prev => {
208→      const next = [
209→        char,
210→        ...prev.filter(c => c !== char),
211→      ].slice(0, MAX_RECENT);
212→      settingsDb.set(DB_KEY, JSON.stringify(next)).catch(console.error);
213→      return next;
214→    });
215→  }, []);
216→
217→  const handleCopyEmoji = useCallback(
218→    (emoji?: EmojiEntry) => {
219→      const target = emoji ?? selectedEmoji;
220→      if (!target) return;
221→      setActionsOpen(false);
222→      performCopy(target.char, showHUD, {
223→        hudTitle: `Copied ${target.char}`,
224→        onCopy: () => addToRecent(target.char),
225→      });
226→    },
227→    [
228→      selectedEmoji,
229→      showHUD,
230→      addToRecent,
231→    ],
232→  );
233→
234→  const handleQueryChange = useCallback((value: string) => {
235→    setQuery(value);
236→    setActiveIndex(0);
237→    setActionsOpen(false);
238→  }, []);
239→
240→  const handleFilterChange = useCallback((value: string) => {
241→    setFilterValue(value);
242→    setActiveIndex(0);
243→  }, []);
244→
245→  const toggleActions = useCallback(() => {
246→    setActionsOpen(prev => !prev);
247→  }, []);
248→
249→  const closeActions = useCallback(() => {
250→    setActionsOpen(false);
251→  }, []);
252→
253→  useKeyboardShortcut(
254→    {
255→      key: 'k',
256→      meta: true,
257→    },
258→    toggleActions,
259→  );
260→  useKeyboardShortcut(
261→    {
262→      key: 'c',
263→      meta: true,
264→    },
265→    () => handleCopyEmoji(),
266→  );
267→  useKeyboardShortcut(
268→    {
269→      key: 'l',
270→      meta: true,
271→    },
272→    () => handleCopyEmoji(),
273→  );
274→
275→  useEffect(() => {
276→    function handleKeyDown(e: KeyboardEvent) {
277→      if (totalCount === 0) return;
278→      if (actionsOpen) return;
279→      if (e.metaKey || e.ctrlKey || e.altKey) return;
280→
281→      const isTextInput =
282→        e.target instanceof HTMLInputElement ||
283→        e.target instanceof HTMLTextAreaElement;
284→
285→      switch (e.key) {
286→        case 'ArrowRight': {
287→          if (isTextInput) return;
288→          e.preventDefault();
289→          setActiveIndex(prev => (prev + 1 < totalCount ? prev + 1 : 0));
290→          break;
291→        }
292→        case 'ArrowLeft': {
293→          if (isTextInput) return;
294→          e.preventDefault();
295→          setActiveIndex(prev => (prev - 1 >= 0 ? prev - 1 : totalCount - 1));
296→          break;
297→        }
298→        case 'ArrowDown': {
299→          e.preventDefault();
300→          setActiveIndex(prev => {
301→            const sectionInfo = getSectionInfo(prev);
302→            if (!sectionInfo) return prev;
303→            const { sectionStart, sectionLength } = sectionInfo;
304→            const posInSection = prev - sectionStart;
305→            const row = Math.floor(posInSection / COLUMNS);
306→            const col = posInSection % COLUMNS;
307→            const sectionRows = Math.ceil(sectionLength / COLUMNS);
308→
309→            if (row + 1 < sectionRows) {
310→              const nextIdx = sectionStart + (row + 1) * COLUMNS + col;
311→              return nextIdx < sectionStart + sectionLength
312→                ? nextIdx
313→                : sectionStart + sectionLength - 1;
314→            }
315→
316→            const nextSectionStart = sectionStart + sectionLength;
317→            if (nextSectionStart < totalCount) {
318→              const nextInfo = getSectionInfo(nextSectionStart);
319→              if (!nextInfo) return prev;
320→              const targetIdx = nextSectionStart + col;
321→              return targetIdx < nextSectionStart + nextInfo.sectionLength
322→                ? targetIdx
323→                : nextSectionStart + nextInfo.sectionLength - 1;
324→            }
325→
326→            return prev;
327→          });
328→          break;
329→        }
330→        case 'ArrowUp': {
331→          e.preventDefault();
332→          setActiveIndex(prev => {
333→            const sectionInfo = getSectionInfo(prev);
334→            if (!sectionInfo) return prev;
335→            const { sectionStart } = sectionInfo;
336→            const posInSection = prev - sectionStart;
337→            const row = Math.floor(posInSection / COLUMNS);
338→            const col = posInSection % COLUMNS;
339→
340→            if (row > 0) {
341→              return sectionStart + (row - 1) * COLUMNS + col;
342→            }
343→
344→            if (sectionStart > 0) {
345→              const prevSectionEnd = sectionStart - 1;
346→              const prevInfo = getSectionInfo(prevSectionEnd);
347→              if (!prevInfo) return prev;
348→              const prevSectionRows = Math.ceil(
349→                prevInfo.sectionLength / COLUMNS,
350→              );
351→              const lastRowStart =
352→                prevInfo.sectionStart + (prevSectionRows - 1) * COLUMNS;
353→              const targetIdx = lastRowStart + col;
354→              return targetIdx < prevInfo.sectionStart + prevInfo.sectionLength
355→                ? targetIdx
356→                : prevInfo.sectionStart + prevInfo.sectionLength - 1;
357→            }
358→
359→            return prev;
360→          });
361→          break;
362→        }
363→        case 'Enter': {
364→          e.preventDefault();
365→          handleCopyEmoji();
366→          break;
367→        }
368→      }
369→    }
370→
371→    window.addEventListener('keydown', handleKeyDown);
372→    return () => window.removeEventListener('keydown', handleKeyDown);
373→  }, [
374→    totalCount,
375→    actionsOpen,
376→    handleCopyEmoji,
377→    sections,
378→  ]);
379→
380→  const sectionBoundaries = useMemo(() => {
381→    const boundaries: {
382→      start: number;
383→      length: number;
384→    }[] = [];
385→    let offset = 0;
386→    for (const section of sections) {
387→      boundaries.push({
388→        start: offset,
389→        length: section.emojis.length,
390→      });
391→      offset += section.emojis.length;
392→    }
393→    return boundaries;
394→  }, [sections]);
395→
396→  function getSectionInfo(index: number) {
397→    for (const b of sectionBoundaries) {
398→      if (index >= b.start && index < b.start + b.length) {
399→        return {
400→          sectionStart: b.start,
401→          sectionLength: b.length,
402→        };
