 153→function entryToRow(entry: QuicklinkEntry): QuicklinkRow {
 154→  return {
 155→    id: entry.id,
 156→    name: entry.name,
 157→    link: entry.link,
 158→    type: entry.type,
 159→    application: entry.application ?? null,
 160→    tags: entry.tags ? JSON.stringify(entry.tags) : '[]',
 161→    created_at: entry.createdAt.toISOString(),
 162→  };
 163→}
