 444→  const [query, setQuery] = useState('');
 445→  const [filterValue, setFilterValue] = useState('all');
 446→  const [selectedIndex, setSelectedIndex] = useState(0);
 447→  const [actionsOpen, setActionsOpen] = useState(false);
 448→  const [subView, setSubView] = useState<
 449→    'list' | 'edit' | 'create' | 'query-input'
