 454→  const [queryInputEntry, setQueryInputEntry] = useState<
 455→    QuicklinkEntry | undefined
 456→  >();
 457→  const { items: hudItems, show: showHUD } = useHUD();
 458→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
 459→  const now = useMemo(() => new Date(), []);
 460→
 461→  useEffect(() => {
 462→    let aborted = false;
 463→
 464→    quicklinkDb
 465→      .getAll()
 466→      .then(rows => {
 467→        if (aborted) return;
 468→        if (rows.length > 0) {
 469→          setEntries(rows.map(rowToEntry));
 470→        } else if (!isTauri) {
 471→          const mock = MOCK_QUICKLINKS.map(e => ({ ...e }));
 472→          setEntries(mock);
 473→          Promise.all(mock.map(e => quicklinkDb.insert(entryToRow(e)))).catch(
 474→            console.error,
 475→          );
 476→        }
 477→      })
 478→      .catch(err => {
 479→        console.error('Failed to load quicklinks:', err);
 480→        if (!isTauri && !aborted) {
 481→          setEntries(MOCK_QUICKLINKS.map(e => ({ ...e })));
 482→        }
 483→      });
 484→
 485→    return () => {
 486→      aborted = true;
 487→    };
 488→  }, []);
 489→
 490→  const dbSearchFn = useCallback((q: string) => quicklinkDb.search(q), []);
 491→  const { results: ftsResults, invalidate: invalidateFts } = useDbSearch(
 492→    query,
 493→    dbSearchFn,
 494→    rowToEntry,
 495→  );
 496→
 497→  const filtered = useMemo(() => {
 498→    let items = ftsResults ?? entries;
 499→    if (filterValue !== 'all') {
 500→      items = items.filter(e => e.type === filterValue);
 501→    }
 502→    if (!ftsResults && query) {
 503→      items = items.filter(
 504→        e => fuzzyMatch(query, e.name) || fuzzyMatch(query, e.link),
 505→      );
 506→    }
 507→    return items;
 508→  }, [
 509→    entries,
 510→    query,
 511→    filterValue,
 512→    ftsResults,
 513→  ]);
 514→
 515→  const urlItems = useMemo(
 516→    () => filtered.filter(e => e.type === 'url'),
 517→    [filtered],
 518→  );
 519→  const fileItems = useMemo(
 520→    () => filtered.filter(e => e.type === 'file'),
 521→    [filtered],
 522→  );
 523→  const deeplinkItems = useMemo(
 524→    () => filtered.filter(e => e.type === 'deeplink'),
 525→    [filtered],
 526→  );
 527→
 528→  const flatItems = useMemo(
 529→    () => [
 530→      ...urlItems,
 531→      ...fileItems,
 532→      ...deeplinkItems,
 533→    ],
 534→    [
 535→      urlItems,
 536→      fileItems,
 537→      deeplinkItems,
 538→    ],
 539→  );
 540→  const totalItemCount = flatItems.length;
 541→
 542→  useEffect(() => {
 543→    if (selectedIndex >= totalItemCount && totalItemCount > 0) {
 544→      setSelectedIndex(totalItemCount - 1);
 545→    } else if (totalItemCount === 0) {
 546→      setSelectedIndex(0);
 547→    }
 548→  }, [
 549→    selectedIndex,
 550→    totalItemCount,
 551→  ]);
 552→
 553→  const selectedEntry = flatItems[selectedIndex];
 554→
 555→  const handleQueryChange = useCallback((value: string) => {
 556→    setQuery(value);
 557→    setSelectedIndex(0);
 558→    setActionsOpen(false);
 559→  }, []);
 560→
 561→  const handleFilterChange = useCallback((value: string) => {
 562→    setFilterValue(value);
 563→    setSelectedIndex(0);
 564→  }, []);
 565→
 566→  const handleActiveIndexChange = useCallback((index: number) => {
 567→    setSelectedIndex(index);
 568→    setActionsOpen(false);
 569→  }, []);
 570→
 571→  const handleOpen = useCallback(() => {
 572→    if (!selectedEntry) return;
 573→    setActionsOpen(false);
 574→    const link = selectedEntry.link;
 575→    if (link.includes('{query}')) {
 576→      setQueryInputEntry(selectedEntry);
 577→      setSubView('query-input');
 578→      return;
 579→    }
