121→function truncateContent(content: string, maxLength: number): string {
122→  const singleLine = content.replace(/\n/g, ' ');
123→  if (singleLine.length <= maxLength) return singleLine;
124→  return singleLine.slice(0, maxLength) + '\u2026';
125→}
